diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 9ff1e3aa5502..957fc358621f 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -5155,6 +5155,121 @@ Instruction *InstCombinerImpl::foldICmpBinOp(ICmpInst &I,
     }
   }

+  //
+  // Handle icmp (div X, C), X  and  icmp X, (div X, C)
+  // where C is a constant greater than 1.
+  //
+  // For signed division with C > 1:
+  //   (X s/ C) slt X  -->  X sgt 0
+  //   (X s/ C) sle X  -->  X sgt 0  (if X != 0, which is true when X/C < X)
+  //   X slt (X s/ C)  -->  X slt 0
+  //   X sle (X s/ C)  -->  X slt 0
+  //   (X s/ C) sgt X  -->  X slt 0
+  //   (X s/ C) sge X  -->  X slt 0
+  //   X sgt (X s/ C)  -->  X sgt 0
+  //   X sge (X s/ C)  -->  X sgt 0
+  //
+  // For unsigned division with C > 1:
+  //   (X u/ C) ult X  -->  X != 0
+  //   X ugt (X u/ C)  -->  X != 0
+  //
+  {
+    BinaryOperator *Div = nullptr;
+    // icmp (div X, C), X
+    if (BO0 && (BO0->getOpcode() == Instruction::SDiv ||
+                BO0->getOpcode() == Instruction::UDiv) &&
+        Op1 == BO0->getOperand(0))
+      Div = BO0;
+    // icmp X, (div X, C)
+    else if (BO1 && (BO1->getOpcode() == Instruction::SDiv ||
+                     BO1->getOpcode() == Instruction::UDiv) &&
+             Op0 == BO1->getOperand(0))
+      Div = BO1;
+
+    if (Div) {
+      const APInt *Divisor;
+      if (match(Div->getOperand(1), m_APInt(Divisor))) {
+        // Require |C| > 1 to ensure division actually reduces magnitude
+        // (C == 1 is no-op, C == -1 is negation)
+        if (Divisor->ugt(1) || Divisor->slt(-1)) {
+          bool DivIsSigned = Div->getOpcode() == Instruction::SDiv;
+          // Determine if it's (div X, C) op X or X op (div X, C)
+          if (Div == BO0) {
+            // (div X, C) op X
+            if (DivIsSigned) {
+              // For signed division: (X / C) < X  -->  X > 0
+              //                      (X / C) > X  -->  X < 0
+              switch (Pred) {
+              case ICmpInst::ICMP_SLT:
+              case ICmpInst::ICMP_SLE:
+                return new ICmpInst(ICmpInst::ICMP_SGT, Op1,
+                                    Constant::getNullValue(Op1->getType()));
+              case ICmpInst::ICMP_SGT:
+              case ICmpInst::ICMP_SGE:
+                return new ICmpInst(ICmpInst::ICMP_SLT, Op1,
+                                    Constant::getNullValue(Op1->getType()));
+              default:
+                break;
+              }
+            } else {
+              // For unsigned division: (X / C) < X  -->  X != 0
+              //                        (X / C) > X  -->  false
+              switch (Pred) {
+              case ICmpInst::ICMP_ULT:
+              case ICmpInst::ICMP_ULE:
+                return new ICmpInst(ICmpInst::ICMP_NE, Op1,
+                                    Constant::getNullValue(Op1->getType()));
+              case ICmpInst::ICMP_UGT:
+              case ICmpInst::ICMP_UGE:
+                return replaceInstUsesWith(
+                    I, Divisor->isStrictlyPositive()
+                           ? ConstantInt::getFalse(I.getType())
+                           : ConstantInt::getTrue(I.getType()));
+              default:
+                break;
+              }
+            }
+          } else {
+            // X op (div X, C)
+            if (DivIsSigned) {
+              // For signed division: X < (X / C)  -->  X < 0
+              //                      X > (X / C)  -->  X > 0
+              switch (Pred) {
+              case ICmpInst::ICMP_SLT:
+              case ICmpInst::ICMP_SLE:
+                return new ICmpInst(ICmpInst::ICMP_SLT, Op0,
+                                    Constant::getNullValue(Op0->getType()));
+              case ICmpInst::ICMP_SGT:
+              case ICmpInst::ICMP_SGE:
+                return new ICmpInst(ICmpInst::ICMP_SGT, Op0,
+                                    Constant::getNullValue(Op0->getType()));
+              default:
+                break;
+              }
+            } else {
+              // For unsigned division: X < (X / C)  -->  false (when C > 1)
+              //                        X > (X / C)  -->  X != 0
+              switch (Pred) {
+              case ICmpInst::ICMP_ULT:
+              case ICmpInst::ICMP_ULE:
+                return replaceInstUsesWith(
+                    I, Divisor->isStrictlyPositive()
+                           ? ConstantInt::getFalse(I.getType())
+                           : ConstantInt::getTrue(I.getType()));
+              case ICmpInst::ICMP_UGT:
+              case ICmpInst::ICMP_UGE:
+                return new ICmpInst(ICmpInst::ICMP_NE, Op0,
+                                    Constant::getNullValue(Op0->getType()));
+              default:
+                break;
+              }
+            }
+          }
+        }
+      }
+    }
+  }
+
   if (BO0 && BO1 && BO0->getOpcode() == BO1->getOpcode() &&
       (BO0->hasOneUse() || BO1->hasOneUse()) &&
       BO0->getOperand(1) == BO1->getOperand(1)) {

